{
  "command": "set -e
TMP=$(mktemp -d)
export PI_CODING_AGENT_DIR="$TMP"
unset YPI_GITHUB_APP_ID YPI_GITHUB_APP_PRIVATE_KEY_FILE YPI_GITHUB_APP_WEBHOOK_SECRET YPI_GITHUB_APP_SLUG

node --input-type=module <<'EOF'
import { generateKeyPairSync } from 'node:crypto';
import { chmod, lstat, readFile, readdir, symlink, writeFile, mkdir, rm } from 'node:fs/promises';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { createJiti } from 'jiti';

const root = process.cwd();
const jiti = createJiti(join(root, 'package.json'), { interopDefault: true });
const store = jiti(join(root, 'lib/github-app-credential-store.ts'));

const { privateKey } = generateKeyPairSync('rsa', { modulusLength: 2048 });
const pem = privateKey.export({ type: 'pkcs8', format: 'pem' }).toString();
const appId = '123456';
const secret = 'whsec_test_local_only_' + Math.random().toString(36).slice(2);

// 1) First save requires complete bundle
let failed = false;
try {
  await store.upsertGithubAppLocalCredentials({ appId });
  failed = true;
} catch {}
if (failed) throw new Error('partial first save should fail');

const summary1 = await store.upsertGithubAppLocalCredentials({
  appId,
  webhookSecret: secret,
  privateKeyPem: pem,
  appSlug: 'ypi-test-app',
});
if (!summary1.configured || summary1.readiness !== 'ready') throw new Error('first save not ready');

const loaded = await store.loadGithubAppLocalCredentials();
if (!loaded) throw new Error('load missing after save');
if (loaded.bundle.appId !== appId) throw new Error('appId mismatch');
if (loaded.bundle.webhookSecret !== secret) throw new Error('secret mismatch');
if (loaded.bundle.appSlug !== 'ypi-test-app') throw new Error('slug mismatch');

// 2) Modes 0700/0600
const agentRoot = process.env.PI_CODING_AGENT_DIR;
const autoRoot = join(agentRoot, 'github-automation');
const metaPath = join(autoRoot, 'credentials.v1.json');
const keyPath = loaded.privateKeyPath;
const metaMode = (await lstat(metaPath)).mode & 0o777;
const keyMode = (await lstat(keyPath)).mode & 0o777;
const dirMode = (await lstat(autoRoot)).mode & 0o777;
if (dirMode !== 0o700) throw new Error('root not 0700: ' + dirMode.toString(8));
if (metaMode !== 0o600) throw new Error('meta not 0600: ' + metaMode.toString(8));
if (keyMode !== 0o600) throw new Error('key not 0600: ' + keyMode.toString(8));

// 3) Partial rotation preserves secret
const { privateKey: pk2 } = generateKeyPairSync('rsa', { modulusLength: 2048 });
const pem2 = pk2.export({ type: 'pkcs8', format: 'pem' }).toString();
const oldKey = loaded.bundle.keyFile;
await store.upsertGithubAppLocalCredentials({ privateKeyPem: pem2 });
const loaded2 = await store.loadGithubAppLocalCredentials();
if (!loaded2) throw new Error('missing after rotate');
if (loaded2.bundle.webhookSecret !== secret) throw new Error('secret not preserved');
if (loaded2.bundle.appId !== appId) throw new Error('appId not preserved');
if (loaded2.bundle.keyFile === oldKey) throw new Error('key generation not switched');
const entries = await readdir(autoRoot);
if (entries.includes(oldKey)) throw new Error('old generation not cleaned');

// 4) Safe summary has no secrets
const safe = await store.getGithubAppLocalCredentialSafeSummary();
const safeJson = JSON.stringify(safe);
if (safeJson.includes(secret) || safeJson.includes(appId) || safeJson.includes('BEGIN')) {
  throw new Error('safe summary leaked material');
}

// 5) Unknown schema fail closed
await writeFile(metaPath, JSON.stringify({
  schemaVersion: 99,
  kind: 'ypi-github-app-local-credentials',
  appId: '9',
  webhookSecret: 'x',
  appSlug: null,
  keyFile: loaded2.bundle.keyFile,
  keySha256: loaded2.bundle.keySha256,
  createdAt: new Date().toISOString(),
  updatedAt: new Date().toISOString(),
}, null, 2), { mode: 0o600 });

const safeU = await store.getGithubAppLocalCredentialSafeSummary();
if (safeU.readiness !== 'unsupported') throw new Error('future schema not unsupported: ' + safeU.readiness);

failed = false;
try {
  await store.upsertGithubAppLocalCredentials({ appId: '42', webhookSecret: 'y', privateKeyPem: pem });
  failed = true;
} catch {}
if (failed) throw new Error('upsert must not overwrite future schema');

// 6) Delete recovers
const del = await store.deleteGithubAppLocalCredentials();
if (del.readiness !== 'missing') throw new Error('delete not missing');
const afterDel = await store.loadGithubAppLocalCredentials();
if (afterDel !== null) throw new Error('load after delete should be null');
const afterEntries = await readdir(autoRoot);
if (afterEntries.includes('credentials.v1.json')) throw new Error('metadata remains');
for (const e of afterEntries) {
  if (e.startsWith('private-key.')) throw new Error('key remains: ' + e);
}

// 7) config.json / jobs untouched by delete
await writeFile(join(autoRoot, 'config.json'), '{"keep":true}\n', { mode: 0o600 });
await mkdir(join(autoRoot, 'jobs'), { recursive: true, mode: 0o700 });
await writeFile(join(autoRoot, 'jobs', 'x.json'), '{}\n', { mode: 0o600 });
await store.upsertGithubAppLocalCredentials({ appId, webhookSecret: secret, privateKeyPem: pem });
await store.deleteGithubAppLocalCredentials();
const cfg = await readFile(join(autoRoot, 'config.json'), 'utf8');
if (!cfg.includes('keep')) throw new Error('config.json damaged');
const job = await readFile(join(autoRoot, 'jobs', 'x.json'), 'utf8');
if (!job.includes('{}')) throw new Error('jobs damaged');

// 8) Symlink key rejected
await store.upsertGithubAppLocalCredentials({ appId, webhookSecret: secret, privateKeyPem: pem });
const again = await store.loadGithubAppLocalCredentials();
const realKey = again.privateKeyPath;
const evil = join(autoRoot, 'evil.pem');
await writeFile(evil, pem, { mode: 0o600 });
await rm(realKey, { force: true });
await symlink(evil, realKey);
failed = false;
try {
  await store.loadGithubAppLocalCredentials();
  failed = true;
} catch {}
if (failed) throw new Error('symlink key should fail closed');

await store.deleteGithubAppLocalCredentials();

// 9) non-RSA rejected on upsert
const { privateKey: ecKey } = generateKeyPairSync('ec', { namedCurve: 'P-256' });
const ecPem = ecKey.export({ type: 'pkcs8', format: 'pem' }).toString();
failed = false;
try {
  await store.upsertGithubAppLocalCredentials({ appId, webhookSecret: secret, privateKeyPem: ecPem });
  failed = true;
} catch {}
if (failed) throw new Error('EC key should be rejected');

// 10) containment
failed = false;
try {
  store.resolveGithubAppCredentialKeyPath('../private-key.abc.pem');
  failed = true;
} catch {}
if (failed) throw new Error('traversal basename should fail');
failed = false;
try {
  store.resolveGithubAppCredentialKeyPath('/tmp/private-key.abc.pem');
  failed = true;
} catch {}
if (failed) throw new Error('absolute basename should fail');

// 11) concurrent writes serialize and leave one valid bundle
await store.upsertGithubAppLocalCredentials({ appId, webhookSecret: secret, privateKeyPem: pem });
const { privateKey: pkA } = generateKeyPairSync('rsa', { modulusLength: 2048 });
const { privateKey: pkB } = generateKeyPairSync('rsa', { modulusLength: 2048 });
const pemA = pkA.export({ type: 'pkcs8', format: 'pem' }).toString();
const pemB = pkB.export({ type: 'pkcs8', format: 'pem' }).toString();
await Promise.all([
  store.upsertGithubAppLocalCredentials({ privateKeyPem: pemA }),
  store.upsertGithubAppLocalCredentials({ privateKeyPem: pemB }),
]);
const final = await store.loadGithubAppLocalCredentials();
if (!final) throw new Error('missing after concurrent');
// only one active key generation matching metadata
const gens = (await readdir(autoRoot)).filter((n) => n.startsWith('private-key.') && n.endsWith('.pem'));
if (gens.length !== 1) throw new Error('expected single generation, got ' + gens.join(','));
if (gens[0] !== final.bundle.keyFile) throw new Error('active key mismatch');

// malformed metadata fail closed
await writeFile(metaPath, '{not-json', { mode: 0o600 });
const safeM = await store.getGithubAppLocalCredentialSafeSummary();
if (safeM.readiness !== 'invalid') throw new Error('malformed not invalid');
failed = false;
try {
  await store.upsertGithubAppLocalCredentials({ appId, webhookSecret: secret, privateKeyPem: pem });
  failed = true;
} catch {}
if (failed) throw new Error('upsert must not overwrite malformed');
await store.deleteGithubAppLocalCredentials();

console.log('GHCRED-01 store lifecycle OK');
console.log(store._testGithubAppCredentialStoreLockConfig());
EOF
